using System.ComponentModel.DataAnnotations;

namespace sv_0dcad055fe234f8abeb5c75df79cc66e.Models;

public class ReviewModel
{
    [Required(ErrorMessage = "Product name is required.")]
    public string ProductName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Rating is required.")]
    [Range(1, 5, ErrorMessage = "Rating must be between 1 and 5.")]
    public int? Rating { get; set; }

    [Required(ErrorMessage = "Review title is required.")]
    [MaxLength(100, ErrorMessage = "Review title cannot exceed 100 characters.")]
    public string ReviewTitle { get; set; } = string.Empty;

    [Required(ErrorMessage = "Review body is required.")]
    [MaxLength(2000, ErrorMessage = "Review body cannot exceed 2000 characters.")]
    public string ReviewBody { get; set; } = string.Empty;
}

namespace sv_0dcad055fe234f8abeb5c75df79cc66e.Services;

using sv_0dcad055fe234f8abeb5c75df79cc66e.Models;

public class ReviewService
{
    /// <summary>
    /// Validates the review against server-side business rules and submits it if valid.
    /// Returns a dictionary of field-specific errors (field name → error message).
    /// An empty dictionary means success.
    /// </summary>
    public Task<Dictionary<string, string>> ValidateAndSubmitAsync(ReviewModel review, List<PhotoInfo>? photos)
    {
        var errors = new Dictionary<string, string>();

        if (review.ReviewTitle.Contains("spam", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(review.ReviewTitle)] = "Review title contains inappropriate language.";
        }

        // Additional server-side rules can be added here.

        // If no errors, the review is "submitted" (stub — no persistence).
        return Task.FromResult(errors);
    }
}

public class PhotoInfo
{
    public string FileName { get; set; } = string.Empty;
    public long Size { get; set; }
}

@page "/write-review"
@rendermode InteractiveServer
@using sv_0dcad055fe234f8abeb5c75df79cc66e.Models
@using sv_0dcad055fe234f8abeb5c75df79cc66e.Services
@inject ReviewService ReviewService

<h3>Write a Review</h3>

@if (_submitted)
{
    <div class="alert alert-success">Your review has been submitted successfully!</div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="write-review">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label class="form-label">Product Name</label>
            <InputText class="form-control" @bind-Value="_model.ProductName" />
            <ValidationMessage For="() => _model.ProductName" />
            @if (_serverErrors.ContainsKey(nameof(_model.ProductName)))
            {
                <div class="text-danger">@_serverErrors[nameof(_model.ProductName)]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Rating (1–5)</label>
            <InputNumber class="form-control" @bind-Value="_model.Rating" />
            <ValidationMessage For="() => _model.Rating" />
            @if (_serverErrors.ContainsKey(nameof(_model.Rating)))
            {
                <div class="text-danger">@_serverErrors[nameof(_model.Rating)]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Review Title</label>
            <InputText class="form-control" @bind-Value="_model.ReviewTitle" />
            <ValidationMessage For="() => _model.ReviewTitle" />
            @if (_serverErrors.ContainsKey(nameof(_model.ReviewTitle)))
            {
                <div class="text-danger">@_serverErrors[nameof(_model.ReviewTitle)]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Review Body</label>
            <InputTextArea class="form-control" rows="5" @bind-Value="_model.ReviewBody" />
            <ValidationMessage For="() => _model.ReviewBody" />
            @if (_serverErrors.ContainsKey(nameof(_model.ReviewBody)))
            {
                <div class="text-danger">@_serverErrors[nameof(_model.ReviewBody)]</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label">Photos (up to 3, JPG/PNG, max 5 MB each)</label>
            <InputFile OnChange="OnPhotosSelected" multiple accept=".jpg,.jpeg,.png" class="form-control" />
            @if (_photoError is not null)
            {
                <div class="text-danger">@_photoError</div>
            }
            @if (_photos.Count > 0)
            {
                <ul class="mt-2 list-group">
                    @foreach (var photo in _photos)
                    {
                        <li class="list-group-item">@photo.FileName — @FormatSize(photo.Size)</li>
                    }
                </ul>
            }
        </div>

        <button type="submit" class="btn btn-primary" disabled="@_isSubmitting">
            @if (_isSubmitting)
            {
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Review</span>
            }
        </button>
    </EditForm>
}

@code {
    private ReviewModel _model = new();
    private List<PhotoInfo> _photos = new();
    private Dictionary<string, string> _serverErrors = new();
    private string? _photoError;
    private bool _submitted;
    private bool _isSubmitting;

    private const long MaxFileSize = 5 * 1024 * 1024; // 5 MB
    private const int MaxFileCount = 3;
    private static readonly string[] AllowedExtensions = [".jpg", ".jpeg", ".png"];

    private void OnPhotosSelected(InputFileChangeEventArgs e)
    {
        _photoError = null;
        _photos.Clear();

        if (e.FileCount > MaxFileCount)
        {
            _photoError = $"You can upload at most {MaxFileCount} photos.";
            return;
        }

        foreach (var file in e.GetMultipleFiles(MaxFileCount))
        {
            var ext = Path.GetExtension(file.Name).ToLowerInvariant();
            if (!AllowedExtensions.Contains(ext))
            {
                _photoError = $"'{file.Name}' is not a supported format. Only JPG and PNG are allowed.";
                _photos.Clear();
                return;
            }

            if (file.Size > MaxFileSize)
            {
                _photoError = $"'{file.Name}' exceeds the 5 MB size limit.";
                _photos.Clear();
                return;
            }

            _photos.Add(new PhotoInfo { FileName = file.Name, Size = file.Size });
        }
    }

    private async Task HandleSubmit()
    {
        _serverErrors.Clear();
        _isSubmitting = true;

        try
        {
            var errors = await ReviewService.ValidateAndSubmitAsync(_model, _photos);

            if (errors.Count > 0)
            {
                _serverErrors = errors;
            }
            else
            {
                _submitted = true;
            }
        }
        finally
        {
            _isSubmitting = false;
        }
    }

    private static string FormatSize(long bytes)
    {
        if (bytes < 1024) return $"{bytes} B";
        if (bytes < 1024 * 1024) return $"{bytes / 1024.0:F1} KB";
        return $"{bytes / (1024.0 * 1024.0):F2} MB";
    }
}

